import{Body,Controller,Get,Patch,Post,UseGuards}from'@nestjs/common';import{ApiBearerAuth,ApiTags}from'@nestjs/swagger';import{IsBoolean,IsOptional,IsString}from'class-validator';import{CurrentUser}from'../common/decorators/current-user.decorator';import{JwtGuard}from'../common/guards/jwt.guard';import{PrismaService}from'../prisma/prisma.service';
class ApplyDto{@IsString()legalName!:string;@IsString()nidNumber!:string;@IsOptional()@IsString()nidFrontUrl?:string;@IsOptional()@IsString()nidBackUrl?:string;@IsOptional()@IsString()selfieUrl?:string} class AvailabilityDto{@IsBoolean()available!:boolean}
@ApiTags('Vendors')@Controller('vendors')export class VendorsController{constructor(private db:PrismaService){}@Get('discover')discover(){return this.db.vendorProfile.findMany({where:{status:'APPROVED'},include:{user:{select:{profile:true}}},take:50})}@ApiBearerAuth()@UseGuards(JwtGuard)@Post('apply')apply(@CurrentUser()u:{sub:string},@Body()d:ApplyDto){return this.db.vendorProfile.upsert({where:{userId:u.sub},create:{userId:u.sub,status:'SUBMITTED',...d},update:{status:'SUBMITTED',...d}})}@ApiBearerAuth()@UseGuards(JwtGuard)@Patch('availability')availability(@CurrentUser()u:{sub:string},@Body()d:AvailabilityDto){return this.db.vendorProfile.update({where:{userId:u.sub},data:{availableForCall:d.available}})}}
